parameters.jsCode:
const structuredPrompt = $input.first().json.output.final_prompt;
return {
  json: {
    prompt: JSON.stringify(structuredPrompt), // this escapes it correctly!
    model: "veo3_fast",
    aspectRatio: "16:9"
  }
};

const items = $input.all();

let prompt = "";
const urls = [];

function extractUrl(str) {
  if (!str) return null;
  const m = String(str).match(/https?:\/\/[^\s",\]\)]+/i);
  return m ? m[0] : null;
}

for (const item of items) {
  const j = item.json || {};

  if (!prompt && j["Image Prompt"]) {
    prompt = j["Image Prompt"];
  }

  for (const key of Object.keys(j)) {
    const maybe = extractUrl(j[key]);
    if (maybe && !urls.includes(maybe)) {
      urls.push(maybe);
    }
  }
}

const payloadObject = {
  model: "nano-banana-pro",
  input: {
    prompt: prompt,
    aspect_ratio: "1:1",
    resolution: "4K",
    output_format: "png",
    image_input: urls.slice(0, 4),
  },
};

// ✅ Pretty-printed, human-readable, same indentation style
return [
  {
    json: {
      payload: JSON.stringify(payloadObject, null, 2),
    },
  },
];

